final:
module top_module(input wire clk, vgae2, 
                input wire [7:0] e,
                output wire [3:0] num);reg [3:0] obf_aux;

  always @(e, vgae2) 
  begin
    if (vgae2) 
    begin
      case (e[3:0])              
        4'b0000: obf_aux = 0;
        4'b0001: obf_aux = 1;
        4'b0010: obf_aux = 2;
        4'b0011: obf_aux = 3;
        4'b0100: obf_aux = 4;
        4'b0101: obf_aux = 5;
        4'b0110: obf_aux = 6;
        4'b0111: obf_aux = 7;
        4'b1000: obf_aux = 8;
        4'b1001: obf_aux = 9;
        default: obf_aux = 15;  
      endcase
    end      
  end

  assign num = obf_aux;

endmodule
